+  // Demonstrate LIFO recycling determinism: within a single runtime,
+  // the free-list recycles slots in LIFO order. We create scopes, close them,
+  // then create new ones and verify they reuse the most-recently-freed slots first.
+  const rt = (a.runtimeCreate || a.runtime_create)();
+  if (rt.outcome !== 'ok') return;
+
+  const events = [];
+
+  // Phase 1: Create 4 scopes, record their slots
+  const scopes = [];
+  for (let i = 0; i < 4; i++) {
+    const s = rt.value.enterScope('scope-' + i);
+    if (s.outcome === 'ok') {
+      scopes.push(s.value);
