-      <span style="font-size:24px;">${match ? '✓' : '✗'}</span>
-      <div style="font-size:16px;font-weight:700;color:${match?HEX.green:HEX.red};margin-top:4px;">${match ? 'IDENTICAL — Same relative allocation pattern' : 'MISMATCH — Different allocation pattern'}</div>
