+      given the same sequence of operations. Record a failing test's handle operations, replay them on a different machine,
+      and the same slots get assigned in the same order. In tokio, task IDs are opaque and non-deterministic.
     </div>
   `);
   // REVELATION beat: spring pop on the verdict
   if (motionLib) {
     const verdict = document.querySelector('#replay-result [style*="font-size:24px"]');
     if (verdict) motionLib.animate(verdict, { scale: [0, 1.2, 1] }, { type: 'spring', stiffness: 400, damping: 20 });
   }
